40	export class GoogleGenerativeAIImageModel implements ImageModelV3 {
41	  readonly specificationVersion = 'v3';
42	
43	  get maxImagesPerCall(): number {
44	    if (this.settings.maxImagesPerCall != null) {
45	      return this.settings.maxImagesPerCall;
46	    }
47	    // https://docs.cloud.google.com/vertex-ai/generative-ai/docs/models/gemini/2-5-flash-image
48	    if (isGeminiModel(this.modelId)) {
49	      return 10;
50	    }
51	    // https://ai.google.dev/gemini-api/docs/imagen#imagen-model
52	    return 4;
53	  }
54	
55	  get provider(): string {
56	    return this.config.provider;
57	  }
58	
59	  constructor(
60	    readonly modelId: GoogleGenerativeAIImageModelId,
61	    private readonly settings: GoogleGenerativeAIImageSettings,
62	    private readonly config: GoogleGenerativeAIImageModelConfig,
63	  ) {}
64	
65	  async doGenerate(
66	    options: Parameters<ImageModelV3['doGenerate']>[0],
67	  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
68	    // Gemini image models use the language model API internally
69	    if (isGeminiModel(this.modelId)) {
70	      return this.doGenerateGemini(options);
71	    }
72	    return this.doGenerateImagen(options);
73	  }
74	
75	  private async doGenerateImagen(
76	    options: Parameters<ImageModelV3['doGenerate']>[0],
77	  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
78	    const {
79	      prompt,
80	      n = 1,
81	      size,
82	      aspectRatio = '1:1',
83	      seed,
84	      providerOptions,
85	      headers,
86	      abortSignal,
87	      files,
88	      mask,
89	    } = options;
90	    const warnings: Array<SharedV3Warning> = [];
91	
92	    // Imagen API endpoints do not support image editing
93	    if (files != null && files.length > 0) {
94	      throw new Error(
95	        'Google Generative AI does not support image editing with Imagen models. ' +
96	          'Use Google Vertex AI (@ai-sdk/google-vertex) for image editing capabilities.',
97	      );
98	    }
99	
100	    if (mask != null) {
101	      throw new Error(
102	        'Google Generative AI does not support image editing with masks. ' +
103	          'Use Google Vertex AI (@ai-sdk/google-vertex) for image editing capabilities.',
104	      );
105	    }
106	
107	    if (size != null) {
108	      warnings.push({
109	        type: 'unsupported',
110	        feature: 'size',
111	        details:
112	          'This model does not support the `size` option. Use `aspectRatio` instead.',
113	      });
114	    }
115	
116	    if (seed != null) {
117	      warnings.push({
118	        type: 'unsupported',
119	        feature: 'seed',
120	        details:
121	          'This model does not support the `seed` option through this provider.',
122	      });
123	    }
124	
125	    const googleOptions = await parseProviderOptions({
126	      provider: 'google',
127	      providerOptions,
128	      schema: googleImageModelOptionsSchema,
129	    });
130	
131	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
132	
133	    const parameters: Record<string, unknown> = {
134	      sampleCount: n,
135	    };
136	
137	    if (aspectRatio != null) {
138	      parameters.aspectRatio = aspectRatio;
139	    }
140	
141	    if (googleOptions) {
142	      Object.assign(parameters, googleOptions);
143	    }
144	
145	    const body = {
146	      instances: [{ prompt }],
147	      parameters,
148	    };
149	
150	    const { responseHeaders, value: response } = await postJsonToApi<{
151	      predictions: Array<{ bytesBase64Encoded: string }>;
152	    }>({
153	      url: `${this.config.baseURL}/models/${this.modelId}:predict`,
154	      headers: combineHeaders(await resolve(this.config.headers), headers),
155	      body,
156	      failedResponseHandler: googleFailedResponseHandler,
157	      successfulResponseHandler: createJsonResponseHandler(
158	        googleImageResponseSchema,
159	      ),
160	      abortSignal,
161	      fetch: this.config.fetch,
162	    });
163	    return {
164	      images: response.predictions.map(
165	        (p: { bytesBase64Encoded: string }) => p.bytesBase64Encoded,
166	      ),
167	      warnings,
168	      providerMetadata: {
169	        google: {
170	          images: response.predictions.map(() => ({
171	            // Add any prediction-specific metadata here
172	          })),
173	        },
174	      },
175	      response: {
176	        timestamp: currentDate,
177	        modelId: this.modelId,
178	        headers: responseHeaders,
179	      },
180	    };
181	  }
182	
183	  private async doGenerateGemini(
184	    options: Parameters<ImageModelV3['doGenerate']>[0],
185	  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
186	    const {
187	      prompt,
188	      n,
189	      size,
190	      aspectRatio,
191	      seed,
192	      providerOptions,
193	      headers,
194	      abortSignal,
195	      files,
196	      mask,
197	    } = options;
198	    const warnings: Array<SharedV3Warning> = [];
199	
200	    // Gemini does not support mask-based inpainting
201	    if (mask != null) {
202	      throw new Error(
203	        'Gemini image models do not support mask-based image editing.',
204	      );
205	    }
206	
207	    // Gemini does not support generating multiple images per call via n parameter
208	    if (n != null && n > 1) {
209	      throw new Error(
210	        'Gemini image models do not support generating a set number of images per call. Use n=1 or omit the n parameter.',
211	      );
212	    }
213	
214	    if (size != null) {
215	      warnings.push({
216	        type: 'unsupported',
217	        feature: 'size',
218	        details:
219	          'This model does not support the `size` option. Use `aspectRatio` instead.',
220	      });
221	    }
222	
223	    // Build user message content for language model
224	    const userContent: Array<
225	      | { type: 'text'; text: string }
226	      | { type: 'file'; data: string | Uint8Array | URL; mediaType: string }
227	    > = [];
228	
229	    // Add text prompt
230	    if (prompt != null) {
231	      userContent.push({ type: 'text', text: prompt });
232	    }
233	
234	    // Add input images for editing
235	    if (files != null && files.length > 0) {
236	      for (const file of files) {
237	        if (file.type === 'url') {
238	          userContent.push({
239	            type: 'file',
240	            data: new URL(file.url),
241	            mediaType: 'image/*',
242	          });
243	        } else {
244	          userContent.push({
245	            type: 'file',
246	            data:
247	              typeof file.data === 'string'
248	                ? file.data
249	                : new Uint8Array(file.data),
250	            mediaType: file.mediaType,
251	          });
252	        }
253	      }
254	    }
255	
256	    const languageModelPrompt: LanguageModelV3Prompt = [
257	      { role: 'user', content: userContent },
258	    ];
259	
260	    // Instantiate language model
261	    const languageModel = new GoogleGenerativeAILanguageModel(this.modelId, {
262	      provider: this.config.provider,
263	      baseURL: this.config.baseURL,
264	      headers: this.config.headers ?? {},
265	      fetch: this.config.fetch,
266	      generateId: this.config.generateId ?? defaultGenerateId,
267	    });
268	
269	    // Call language model with image-only response modality
270	    const result = await languageModel.doGenerate({
271	      prompt: languageModelPrompt,
272	      seed,
273	      providerOptions: {
274	        google: {
275	          responseModalities: ['IMAGE'],
276	          imageConfig: aspectRatio
277	            ? {
278	                aspectRatio: aspectRatio as NonNullable<
279	                  GoogleLanguageModelOptions['imageConfig']
280	                >['aspectRatio'],
281	              }
282	            : undefined,
283	          ...((providerOptions?.google as Omit<
284	            GoogleLanguageModelOptions,
285	            'responseModalities' | 'imageConfig'
286	          >) ?? {}),
287	        } satisfies GoogleLanguageModelOptions,
288	      },
289	      headers,
290	      abortSignal,
291	    });
292	
293	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
294	
295	    // Extract images from language model response
296	    const images: string[] = [];
297	    for (const part of result.content) {
298	      if (part.type === 'file' && part.mediaType.startsWith('image/')) {
299	        images.push(convertToBase64(part.data));
300	      }
301	    }
302	
303	    return {
304	      images,
305	      warnings,
306	      providerMetadata: {
307	        google: {
308	          images: images.map(() => ({})),
309	        },
310	      },
311	      response: {
312	        timestamp: currentDate,
313	        modelId: this.modelId,
314	        headers: result.response?.headers,
315	      },
316	      usage: result.usage
317	        ? {
318	            inputTokens: result.usage.inputTokens.total,
319	            outputTokens: result.usage.outputTokens.total,
320	            totalTokens:
321	              (result.usage.inputTokens.total ?? 0) +
322	              (result.usage.outputTokens.total ?? 0),
323	          }
324	        : undefined,
325	    };
326	  }
327	}
328	
329	function isGeminiModel(modelId: string): boolean {
330	  return modelId.startsWith('gemini-');
331	}
332	
333	// minimal version of the schema
334	const googleImageResponseSchema = lazySchema(() =>
335	  zodSchema(
336	    z.object({
337	      predictions: z
338	        .array(z.object({ bytesBase64Encoded: z.string() }))
339	        .default([]),
340	    }),
341	  ),
342	);
343	
344	// Note: For the initial GA launch of Imagen 3, safety filters are not configurable.
345	// https://ai.google.dev/gemini-api/docs/imagen#imagen-model
346	const googleImageModelOptionsSchema = lazySchema(() =>
347	  zodSchema(
348	    z.object({
349	      personGeneration: z
350	        .enum(['dont_allow', 'allow_adult', 'allow_all'])
351	        .nullish(),
352	      aspectRatio: z.enum(['1:1', '3:4', '4:3', '9:16', '16:9']).nullish(),
353	    }),
354	  ),
355	);
356	
357	export type GoogleImageModelOptions = InferSchema<
358	  typeof googleImageModelOptionsSchema
359	>;
