30	export interface GoogleGenerativeAIProvider extends ProviderV3 {
31	  (modelId: GoogleGenerativeAIModelId): LanguageModelV3;
32	
33	  languageModel(modelId: GoogleGenerativeAIModelId): LanguageModelV3;
34	
35	  chat(modelId: GoogleGenerativeAIModelId): LanguageModelV3;
36	
37	  /**
38	   * Creates a model for image generation.
39	   */
40	  image(
41	    modelId: GoogleGenerativeAIImageModelId,
42	    settings?: GoogleGenerativeAIImageSettings,
43	  ): ImageModelV3;
44	
45	  /**
46	   * @deprecated Use `chat()` instead.
47	   */
48	  generativeAI(modelId: GoogleGenerativeAIModelId): LanguageModelV3;
