87	export interface GoogleGenerativeAIProviderSettings {
88	  /**
89	   * Use a different URL prefix for API calls, e.g. to use proxy servers.
90	   * The default prefix is `https://generativelanguage.googleapis.com/v1beta`.
91	   */
92	  baseURL?: string;
93	
94	  /**
95	   * API key that is being send using the `x-goog-api-key` header.
96	   * It defaults to the `GOOGLE_GENERATIVE_AI_API_KEY` environment variable.
97	   */
98	  apiKey?: string;
99	
100	  /**
101	   * Custom headers to include in the requests.
102	   */
103	  headers?: Record<string, string | undefined>;
104	
105	  /**
106	   * Custom fetch implementation. You can use it as a middleware to intercept requests,
107	   * or to provide a custom fetch implementation for e.g. testing.
108	   */
109	  fetch?: FetchFunction;
110	
111	  /**
112	   * Optional function to generate a unique ID for each request.
113	   */
114	  generateId?: () => string;
115	
116	  /**
117	   * Custom provider name
118	   * Defaults to 'google.generative-ai'.
119	   */
120	  name?: string;
121	}
122	
123	/**
124	 * Create a Google Generative AI provider instance.
125	 */
126	export function createGoogleGenerativeAI(
127	  options: GoogleGenerativeAIProviderSettings = {},
128	): GoogleGenerativeAIProvider {
129	  const baseURL =
130	    withoutTrailingSlash(options.baseURL) ??
131	    'https://generativelanguage.googleapis.com/v1beta';
132	
133	  const providerName = options.name ?? 'google.generative-ai';
134	
135	  const getHeaders = () =>
136	    withUserAgentSuffix(
137	      {
138	        'x-goog-api-key': loadApiKey({
139	          apiKey: options.apiKey,
140	          environmentVariableName: 'GOOGLE_GENERATIVE_AI_API_KEY',
141	          description: 'Google Generative AI',
142	        }),
143	        ...options.headers,
144	      },
145	      `ai-sdk/google/${VERSION}`,
146	    );
147	
148	  const createChatModel = (modelId: GoogleGenerativeAIModelId) =>
149	    new GoogleGenerativeAILanguageModel(modelId, {
150	      provider: providerName,
151	      baseURL,
152	      headers: getHeaders,
153	      generateId: options.generateId ?? generateId,
154	      supportedUrls: () => ({
155	        '*': [
156	          // Google Generative Language "files" endpoint
157	          // e.g. https://generativelanguage.googleapis.com/v1beta/files/...
158	          new RegExp(`^${baseURL}/files/.*$`),
159	          // YouTube URLs (public or unlisted videos)
160	          new RegExp(
161	            `^https://(?:www\\.)?youtube\\.com/watch\\?v=[\\w-]+(?:&[\\w=&.-]*)?$`,
162	          ),
163	          new RegExp(`^https://youtu\\.be/[\\w-]+(?:\\?[\\w=&.-]*)?$`),
164	        ],
165	      }),
166	      fetch: options.fetch,
167	    });
168	
169	  const createEmbeddingModel = (modelId: GoogleGenerativeAIEmbeddingModelId) =>
170	    new GoogleGenerativeAIEmbeddingModel(modelId, {
171	      provider: providerName,
172	      baseURL,
173	      headers: getHeaders,
174	      fetch: options.fetch,
175	    });
176	
177	  const createImageModel = (
178	    modelId: GoogleGenerativeAIImageModelId,
179	    settings: GoogleGenerativeAIImageSettings = {},
180	  ) =>
181	    new GoogleGenerativeAIImageModel(modelId, settings, {
182	      provider: providerName,
183	      baseURL,
184	      headers: getHeaders,
185	      fetch: options.fetch,
186	    });
187	
188	  const createVideoModel = (modelId: GoogleGenerativeAIVideoModelId) =>
189	    new GoogleGenerativeAIVideoModel(modelId, {
190	      provider: providerName,
191	      baseURL,
192	      headers: getHeaders,
193	      fetch: options.fetch,
194	      generateId: options.generateId ?? generateId,
195	    });
196	
197	  const provider = function (modelId: GoogleGenerativeAIModelId) {
198	    if (new.target) {
199	      throw new Error(
200	        'The Google Generative AI model function cannot be called with the new keyword.',
201	      );
202	    }
203	
204	    return createChatModel(modelId);
205	  };
206	
207	  provider.specificationVersion = 'v3' as const;
208	  provider.languageModel = createChatModel;
209	  provider.chat = createChatModel;
210	  provider.generativeAI = createChatModel;
211	  provider.embedding = createEmbeddingModel;
212	  provider.embeddingModel = createEmbeddingModel;
213	  provider.textEmbedding = createEmbeddingModel;
214	  provider.textEmbeddingModel = createEmbeddingModel;
215	  provider.image = createImageModel;
216	  provider.imageModel = createImageModel;
217	  provider.video = createVideoModel;
218	  provider.videoModel = createVideoModel;
219	  provider.tools = googleTools;
220	
221	  return provider as GoogleGenerativeAIProvider;
222	}
223	
224	/**
225	 * Default Google Generative AI provider instance.
226	 */
227	export const google = createGoogleGenerativeAI();
