### 6. **Provider Factory Pattern (createXxx Function)**

**Example: Google Provider**

**Location:** `/packages/google/src/google-provider.ts` (228 lines)

Pattern overview:
```typescript
export function createGoogleGenerativeAI(
  options: GoogleGenerativeAIProviderSettings = {},
): GoogleGenerativeAIProvider {
  // Load and validate configuration
  const baseURL = withoutTrailingSlash(options.baseURL) ?? 'https://...';
  const providerName = options.name ?? 'google.generative-ai';

  // Create header factory
  const getHeaders = () => withUserAgentSuffix({
    'x-goog-api-key': loadApiKey({...}),
    ...options.headers,
  }, `ai-sdk/google/${VERSION}`);

  // Create factory functions for each model type
  const createImageModel = (
    modelId: GoogleGenerativeAIImageModelId,
    settings: GoogleGenerativeAIImageSettings = {},
  ) =>
    new GoogleGenerativeAIImageModel(modelId, settings, {
      provider: providerName,
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // Implement callable provider function
  const provider = function (modelId: GoogleGenerativeAIModelId) {
    if (new.target) {
      throw new Error('Cannot be called with new keyword.');
    }
    return createChatModel(modelId);
  };

  // Attach all methods
  provider.specificationVersion = 'v3' as const;
  provider.image = createImageModel;
  provider.imageModel = createImageModel;
  provider.languageModel = createChatModel;
  // ... other methods ...
  provider.tools = googleTools;

  return provider as GoogleGenerativeAIProvider;
}

export const google = createGoogleGenerativeAI();
```

**Provider Interface:**
```typescript
