    modelId: GoogleGenerativeAIImageModelId,
    settings?: GoogleGenerativeAIImageSettings,
  ): ImageModelV3;
  imageModel(modelId: GoogleGenerativeAIImageModelId): ImageModelV3;
  embedding(modelId: GoogleGenerativeAIEmbeddingModelId): EmbeddingModelV3;
  video(modelId: GoogleGenerativeAIVideoModelId): Experimental_VideoModelV3;
  tools: typeof googleTools;
}
```

### 7. **Image Model Class Implementation**

**GoogleGenerativeAIImageModel Example:**

**Location:** `/packages/google/src/google-generative-ai-image-model.ts` (360 lines)

Key structure:
```typescript
export class GoogleGenerativeAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    if (this.settings.maxImagesPerCall != null) {
      return this.settings.maxImagesPerCall;
    }
    if (isGeminiModel(this.modelId)) {
      return 10;
    }
    return 4;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: GoogleGenerativeAIImageModelId,
    private readonly settings: GoogleGenerativeAIImageSettings,
    private readonly config: GoogleGenerativeAIImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    // Routes to appropriate implementation based on model
    if (isGeminiModel(this.modelId)) {
      return this.doGenerateGemini(options);
    }
    return this.doGenerateImagen(options);
  }

  private async doGenerateImagen(options): Promise<...> {
    // Handle Imagen API
    const { prompt, n, size, aspectRatio, seed, providerOptions, headers, abortSignal, files, mask } = options;
    const warnings: Array<SharedV3Warning> = [];

    // Validate capabilities and collect warnings
    if (files != null && files.length > 0) {
      throw new Error('Google Generative AI does not support image editing...');
    }

    // Call API
    const { responseHeaders, value: response } = await postJsonToApi({
      url: `${this.config.baseURL}/models/${this.modelId}:predict`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: { instances: [{ prompt }], parameters: {...} },
      failedResponseHandler: googleFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(googleImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.predictions.map(p => p.bytesBase64Encoded),
      warnings,
      providerMetadata: { google: { images: [...] } },
      response: { timestamp: currentDate, modelId: this.modelId, headers: responseHeaders },
    };
  }

  private async doGenerateGemini(options): Promise<...> {
    // Uses language model API internally for image generation
  }
}
```

**OpenAI Image Model Example:**

**Location:** `/packages/openai/src/image/openai-image-model.ts` (350 lines)

```typescript
export class OpenAIImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return modelMaxImagesPerCall[this.modelId] ?? 1;
  }

  constructor(
    readonly modelId: OpenAIImageModelId,
    private readonly config: OpenAIImageModelConfig,
  ) {}

  async doGenerate({
    prompt, files, mask, n, size, aspectRatio, seed, providerOptions, headers, abortSignal
  }): Promise<...> {
    const warnings: Array<SharedV3Warning> = [];

    // Handle image editing vs generation
    if (files != null) {
      // Use /images/edits endpoint with form data
      const { value: response, responseHeaders } = await postFormDataToApi({
        url: this.config.url({ path: '/images/edits', modelId: this.modelId }),
        headers: combineHeaders(this.config.headers(), headers),
        formData: convertToFormData({
          model: this.modelId,
          prompt,
          image: await Promise.all(files.map(file => fileToBlob(file))),
          mask: await fileToBlob(mask),
          n, size,
          ...(providerOptions.openai ?? {}),
        }),
        // ... handler config
      });

      return {
        images: response.data.map(item => item.b64_json),
        warnings,
        usage: {...},
        response: {...},
        providerMetadata: { openai: { images: response.data.map((item, index) => ({...})) } },
      };
    }

    // Regular generation via /images/generations
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({ path: '/images/generations', modelId: this.modelId }),
      headers: combineHeaders(this.config.headers(), headers),
      body: { model: this.modelId, prompt, n, size, ...(providerOptions.openai ?? {}) },
      // ... handler config
    });

    return { images, warnings, usage, response, providerMetadata };
  }
}
