import { ImageModelV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  withoutTrailingSlash,
} from '@ai-sdk/provider-utils';
import {
  PixelArtImageModel,
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-model';

// ------- Provider settings -------

export interface PixelArtProviderSettings {
  /**
   * Base URL for the PixelArt API.
   * Defaults to "https://api.pixelart.ai/v1".
   */
  baseURL?: string;

  /**
   * API key for authenticating with the PixelArt API.
   * Defaults to the value of the `PIXELART_API_KEY` environment variable.
   */
  apiKey?: string;

  /**
   * Additional HTTP headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. Useful for testing or proxying requests.
   */
  fetch?: FetchFunction;
}

// ------- Provider interface -------

export interface PixelArtProvider {
  /**
   * Creates a PixelArt image generation model.
   *
   * @param modelId  The model to use (e.g. "pixelart-v1").
   * @param settings Optional per-model settings (size, style, pixelDensity).
   */
  image(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;

  /**
   * Alias for `image`.
   *
   * @param modelId  The model to use (e.g. "pixelart-v1").
   * @param settings Optional per-model settings (size, style, pixelDensity).
   */
  imageModel(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;
}

// ------- Factory function -------

/**
 * Creates a configured PixelArt provider instance.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixelart';
 *
 * const pixelart = createPixelArt({ apiKey: 'my-api-key' });
 * const model = pixelart.image('pixelart-v1', { style: '8bit' });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? 'https://api.pixelart.ai/v1';

  const getHeaders = (): Record<string, string | undefined> => ({
    Authorization: `Bearer ${loadApiKey({
      apiKey: options.apiKey,
      environmentVariableName: 'PIXELART_API_KEY',
      description: 'PixelArt',
    })}`,
    ...options.headers,
  });

  const createImageModel = (
    modelId: PixelArtImageModelId,
    settings: PixelArtImageSettings = {},
  ): ImageModelV3 =>
    new PixelArtImageModel(modelId, settings, {
      provider: 'pixelart',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    image: createImageModel,
    imageModel: createImageModel,
  };
}

/**
 * Default PixelArt provider instance.
 * Uses the `PIXELART_API_KEY` environment variable for authentication.
 */
export const pixelart = createPixelArt();

