import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  createJsonResponseHandler,
  postJsonToApi,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelartFailedResponseHandler } from './pixelart-error';

// ------- Model IDs -------

export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2-hd'
  | 'pixelart-retro'
  | (string & {});

// ------- Settings -------

export interface PixelArtImageSettings {
  /**
   * The size of the generated image, e.g. "512x512" or "1024x1024".
   * Passed to the API as-is when not overridden by the call-level `size`
   * option.
   */
  size?: string;

  /**
   * The artistic rendering style for the image.
   * - "pixel"  – classic pixel art
   * - "retro"  – retro / CGA-era look
   * - "8bit"   – 8-bit game sprite style
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * Number of pixels per logical unit (dot density).
   * Higher values produce crisper, denser pixel grids.
   */
  pixelDensity?: number;

  /**
   * Maximum number of images that can be requested in a single API call.
   * Defaults to 4.
   */
  maxImagesPerCall?: number;
}

// ------- Internal config -------

export type PixelArtImageModelConfig = {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
};

// ------- Response schema -------

const pixelartImageResponseSchema = z.object({
  data: z.array(
    z.object({
      b64_json: z.string(),
      style: z.string().nullish(),
      width: z.number().nullish(),
      height: z.number().nullish(),
    }),
  ),
  created: z.number().nullish(),
  model: z.string().nullish(),
});

// ------- Image model class -------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return this.settings.maxImagesPerCall ?? 4;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // PixelArt does not support image editing via files/mask
    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'PixelArt does not support image editing with input files.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support inpainting masks.',
      });
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // Merge call-level provider options with model-level settings.
    // Call-level options (providerOptions.pixelart) take precedence.
    const pixelartOptions =
      (providerOptions.pixelart as Partial<PixelArtImageSettings> | undefined) ??
      {};

    const resolvedStyle = pixelartOptions.style ?? this.settings.style;
    const resolvedPixelDensity =
      pixelartOptions.pixelDensity ?? this.settings.pixelDensity;
    const resolvedSize = size ?? pixelartOptions.size ?? this.settings.size;

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(resolvedSize != null ? { size: resolvedSize } : {}),
        ...(aspectRatio != null ? { aspect_ratio: aspectRatio } : {}),
        ...(seed != null ? { seed } : {}),
        ...(resolvedStyle != null ? { style: resolvedStyle } : {}),
        ...(resolvedPixelDensity != null
          ? { pixel_density: resolvedPixelDensity }
          : {}),
      },
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: response.model ?? this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.data.map(item => ({
            ...(item.style != null ? { style: item.style } : {}),
            ...(item.width != null ? { width: item.width } : {}),
            ...(item.height != null ? { height: item.height } : {}),
          })),
          ...(response.created != null ? { created: response.created } : {}),
        },
      },
    };
  }
}

